const data = $input.first().json.body ?? $input.first().json;

// Normaliser le téléphone pour WhatsApp (chiffres uniquement, sans +)
function normalizePhone(phone) {
  return String(phone || '').replace(/[^0-9]/g, '');
}

const livreurPhone = normalizePhone(data.livreur_phone);

if (!livreurPhone) {
  throw new Error('livreur_phone manquant ou invalide : ' + data.livreur_phone);
}

if (!data.phone_number_id || !data.whatsapp_token) {
  throw new Error('Credentials WhatsApp manquants (phone_number_id / whatsapp_token)');
}

const montant = data.total != null
  ? Number(data.total).toLocaleString('fr-FR') + ' FCFA'
  : 'À calculer';

const adresse = data.customer_address || 'Non précisée';
const notes   = data.notes ? `\n📝 Notes : ${data.notes}` : '';

const messageBody = [
  '🛵 *Nouvelle livraison assignée !*',
  '',
  `📦 Commande : ${data.order_number}`,
  `👤 Client : ${data.customer_name}`,
  `📱 Tél. : ${data.customer_phone}`,
  `📍 Adresse : ${adresse}`,
  `💰 Total : ${montant}${notes}`,
  '',
  'Répondez *OK* pour confirmer la prise en charge.'
].join('\n');

return [{
  json: {
    livreur_phone:   livreurPhone,
    message_body:    messageBody,
    phone_number_id: data.phone_number_id,
    whatsapp_token:  data.whatsapp_token,
    order_number:    data.order_number,
    livreur_name:    data.livreur_name
  }
}];

