const result = $input.first().json;
const success = result.messages?.length > 0;

if (!success) {
  console.error('Échec envoi WhatsApp livreur :', JSON.stringify(result));
} else {
  console.log('WhatsApp livreur envoyé :', result.messages[0]?.id);
}

return $input.all();
